var jl_Character_isLetter = ($codePoint) => {
  switch (jl_Character_getType($codePoint)) {
    case 1:
    case 2:
    case 3:
    case 4:
    case 5:
      break;
    default:
      return 0;
  }
  return 1;
};
var jl_Character_isLetterOrDigit = ($codePoint) => {
  a: {
    switch (jl_Character_getType($codePoint)) {
      case 1:
      case 2:
      case 3:
      case 4:
      case 5:
      case 9:
        break;
      case 6:
      case 7:
      case 8:
        break a;
      default:
        break a;
    }
    return 1;
  }
  return 0;
};
var jl_Character_isIdentifierIgnorable = ($codePoint) => {
  a: {
    if (!($codePoint >= 0 && $codePoint <= 8) && !($codePoint >= 14 && $codePoint <= 27)) {
      if ($codePoint < 127)
        break a;
      if ($codePoint > 159)
        break a;
    }
    return 1;
  }
  return jl_Character_getType($codePoint) != 16 ? 0 : 1;
};
var jl_Character_isSpaceChar = ($codePoint) => {
  switch (jl_Character_getType($codePoint)) {
    case 12:
    case 13:
    case 14:
      break;
    default:
      return 0;
  }
  return 1;
};
var jl_Character_isWhitespace = ($codePoint) => {
  switch ($codePoint) {
    case 9:
    case 10:
    case 11:
    case 12:
    case 13:
    case 28:
    case 29:
    case 30:
    case 31:
      break;
    case 160:
    case 8199:
    case 8239:
      return 0;
    default:
      return jl_Character_isSpaceChar($codePoint);
  }
  return 1;
};
